from pathlib import Path
import base64, sys

server = Path(sys.argv[1] if len(sys.argv) > 1 else "server.py")
src = server.read_text(encoding="utf-8")
marker = "# ─── V39 ALS HID TOPOLOGY / REPORT MAP"
if marker in src:
    print("V39 uz je nainstalovana.")
    raise SystemExit(0)

block = base64.b64decode("").decode("utf-8")
needle = "\nif __name__ == '__main__':"
if needle not in src:
    raise SystemExit("Nenalezen main marker v server.py")

backup = server.with_suffix(server.suffix + ".pre_v39.bak")
backup.write_text(src, encoding="utf-8")
src = src.replace(needle, "\n" + block + needle, 1)
server.write_text(src, encoding="utf-8")

print("OK: V39 pridana")
print("Backup:", backup)
print("Endpoint: /api/v39-als-hid-topology/<udid>")
